def categorize_leukocyte(name: str) -> str:
    granulocytes = {'neutrophil', 'eosinophil', 'basophil', 'mast cell'}
    if name.lower() in granulocytes:
        return 'granulocyte'
    else:
        return 'agranulocyte'

# Example usage:
print(categorize_leukocyte('neutrophil'))  # Output: 'granulocyte'
print(categorize_leukocyte('lymphocyte'))  # Output: 'agranulocyte'
